            aOrbiterK = (((aWandererB + RotL64(aPrevious, 37U)) + RotL64(aCarry, 3U)) + 0x46092F4E844C6CA5ULL) + aPhaseFOrbiterAssignSaltA[((aIndex + 25U)) & S_SALT1];
            aOrbiterF = ((aWandererA + RotL64(aScatter, 19U)) + 0x5E3B23AC921EFEF0ULL) + aPhaseFOrbiterAssignSaltE[((aIndex + 5U)) & S_SALT1];
