            aCross = (RotL64(aSnowLaneA[((S_BLOCK1 - aIndex + 6865U)) & S_BLOCK1], 37U) ^ RotL64(aSnowLaneD[((S_BLOCK1 - aIndex + 6070U)) & S_BLOCK1], 5U));
