            aOrbiterF = (((aWandererG + RotL64(aCross, 3U)) + RotL64(aCarry, 57U)) + 0x26968C22E731F7E8ULL) + aPhaseDOrbiterAssignSaltA[((aIndex + 3U)) & S_SALT1];
            aOrbiterA = (aWandererE + RotL64(aScatter, 39U)) + 0x6081858BC9868DCDULL;
            aOrbiterE = ((aWandererC + RotL64(aIngress, 11U)) + RotL64(aCarry, 35U)) + 0x63DCD321FBEBE111ULL;
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 0xC8A4B7625BBCDAC4ULL;
            aOrbiterK = ((aOrbiterK ^ aOrbiterD) ^ 0x0CAFE3A7EAC9D755ULL) ^ aPhaseDOrbiterUpdateSaltD[(((31U - aIndex) + 5U)) & S_SALT1];
            aOrbiterK = RotL64((aOrbiterK * 0x2251C4637A3A1AA5ULL), 3U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterF) + 0x6D68F9B532F48375ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterB) ^ 0xC4AD2D1F3C8C378DULL;
            aOrbiterD = RotL64((aOrbiterD * 0x97AD66E92175B7ADULL), 35U);
