            aOrbiterE = ((aOrbiterE + aOrbiterK) + 0xFB246D84C509650DULL) + aPhaseDOrbiterUpdateSaltF[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 0xB98335BE4B8452A9ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xB0ADB5524404E5EBULL), 23U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 0x0A9D8A22731DD854ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterJ) ^ 0x09858CB81552DAD7ULL;
            aOrbiterB = RotL64((aOrbiterB * 0xFD602CA087ADC099ULL), 53U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterD) + 0x0DC487ECFE393F97ULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterA) ^ 0x849BC528C91548CAULL) ^ aPhaseDOrbiterUpdateSaltE[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0x04663E8BDDDECDFBULL), 29U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterB) + 0x534A9B5208DD23D4ULL) + aPhaseDOrbiterUpdateSaltA[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 0x892C107D21895068ULL;
            aOrbiterA = RotL64((aOrbiterA * 0xBD1A0A671E77C88FULL), 43U);
            //
            aIngress = aOrbiterD ^ RotL64(aOrbiterB, 57U);
            aIngress = aIngress + (RotL64(aOrbiterF, 43U) ^ aOrbiterE);
            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterK, 13U));
            aIngress = aIngress + RotL64(aOrbiterJ, 26U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererA = aWandererA + (((RotL64(aIngress, 19U) + aOrbiterE) + RotL64(aOrbiterK, 11U)) + aPhaseDWandererUpdateSaltB[((aIndex + 28U)) & S_SALT1]);
            aWandererE = aWandererE ^ ((RotL64(aCross, 11U) + RotL64(aOrbiterJ, 37U)) + aOrbiterF);
            aWandererG = aWandererG + (((RotL64(aPrevious, 5U) + aOrbiterD) + RotL64(aOrbiterB, 4U)) + RotL64(aCarry, 57U));
            aWandererC = aWandererC ^ ((RotL64(aScatter, 60U) + RotL64(aOrbiterD, 43U)) + aOrbiterJ);
