            //
            aOrbiterC = ((aOrbiterC + aOrbiterB) + 0xEA64DF84287A3F0DULL) + aPhaseBOrbiterUpdateSaltF[((aIndex + 5U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterC) ^ 0x994B8BE208744273ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xE04430707BEE9979ULL), 43U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 0xF431775D3E93C3D4ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 0x0F32EB983F238E6CULL;
            aOrbiterB = RotL64((aOrbiterB * 0xD82A2271688B298FULL), 27U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterF) + 0xDE4D2252CF9146BEULL) + aPhaseBOrbiterUpdateSaltD[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterJ) ^ 0xD9B58EA8CF1EAA81ULL;
            aOrbiterC = RotL64((aOrbiterC * 0x5A256279396DDCCDULL), 11U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 0x588DC133610A65C1ULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterI) ^ 0xDB8B5175E9B9FACEULL) ^ aPhaseBOrbiterUpdateSaltA[((aIndex + 3U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0x270988989CEDCC95ULL), 23U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterI) + 0xD7B088ACC1D89D2BULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterH) ^ 0xF9C610D49631E860ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x45EA2AAEA544D6E9ULL), 19U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 0x0D70C1AA48AA4451ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterG) ^ 0xE83586E88160F22DULL) ^ aPhaseBOrbiterUpdateSaltE[((aIndex + 21U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0x6A685FD0C473EACBULL), 5U);
            //
            aIngress = RotL64(aOrbiterH, 57U) ^ aOrbiterE;
