            aWandererH = aWandererH + ((((RotL64(aScatter, 10U) + RotL64(aOrbiterH, 47U)) + aOrbiterF) + RotL64(aCarry, 43U)) + aPhaseBWandererUpdateSaltE[((aIndex + 17U)) & S_SALT1]);
            aWandererC = aWandererC ^ ((RotL64(aPrevious, 5U) + RotL64(aOrbiterJ, 11U)) + aOrbiterF);
            aWandererJ = aWandererJ + ((RotL64(aIngress, 35U) + aOrbiterH) + RotL64(aOrbiterI, 56U));
