            aCross = (RotL64(aWorkLaneC[((S_BLOCK1 - aIndex + 2860U)) & S_BLOCK1], 3U) ^ RotL64(aWorkLaneD[((S_BLOCK1 - aIndex + 5428U)) & S_BLOCK1], 54U));
            aCross ^= RotL64(aScrapLaneA[((aIndex + 2519U)) & S_BLOCK1], 27U);
            aCross = TwistMix64::DiffuseB(aCross);
            //
