            aWandererD = aWandererD + ((RotL64(aCross, 27U) + RotL64(aOrbiterJ, 35U)) + aOrbiterK);
            aWandererH = aWandererH ^ ((RotL64(aPrevious, 11U) + RotL64(aOrbiterI, 18U)) + aOrbiterB);
