            aWandererE = aWandererE ^ ((RotL64(aPrevious, 29U) + RotL64(aOrbiterG, 43U)) + aOrbiterH);
            aWandererK = aWandererK + (((RotL64(aIngress, 47U) + aOrbiterA) + RotL64(aOrbiterC, 5U)) + RotL64(aCarry, 57U));
