            //
            aOrbiterK = (aOrbiterK + aOrbiterI) + 0x13E893DD1D7CB16EULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterK) ^ 0x519E5A609B70C3CFULL) ^ aPhaseHOrbiterUpdateSaltF[((aIndex + 9U)) & S_SALT1];
