            //
            aOrbiterK = (aOrbiterK + aOrbiterH) + 0xCD56E8E9B9E09E60ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterK) ^ 0xFC8AFE83BBCC7912ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x0F40E335F837D7EFULL), 11U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterD) + 0xAB6A77D965D99D66ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 0x339F5371D46175C1ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xCA41130665E2D477ULL), 43U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterJ) + 0x3BB16A8F441A36EAULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterI) ^ 0x638ADB4BEEB184DDULL) ^ aPhaseHOrbiterUpdateSaltA[(((31U - aIndex) + 24U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0x42021821D04D562FULL), 3U);
            //
